assertions.query:
SELECT table_schema, table_name, is_typed, user_defined_type_catalog, user_defined_type_schema, user_defined_type_name
FROM information_schema.tables
WHERE table_schema = 'app' AND table_name = 'addresses';

SELECT constraint_name, constraint_type
FROM information_schema.table_constraints
WHERE table_name = 'typed_tasks' AND constraint_type = 'PRIMARY KEY';

SELECT constraint_name, constraint_type
FROM information_schema.table_constraints
WHERE table_name = 'typed_index_option_tasks' AND constraint_type = 'UNIQUE';

SELECT column_name, is_generated
	FROM information_schema.columns
	WHERE table_name = 'typed_generated_tasks' AND column_name = 'area';
